import{_ as e,o as d,c as a,a2 as r}from"./chunks/framework.CuEaBji2.js";const b=JSON.parse('{"title":"Relay 协议内幕","description":"","frontmatter":{},"headers":[],"relativePath":"reference/relay-internals.md","filePath":"reference/relay-internals.md","lastUpdated":1782021666000}'),o={name:"reference/relay-internals.md"};function l(n,t,c,i,h,s){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="relay-协议内幕" tabindex="-1">Relay 协议内幕 <a class="header-anchor" href="#relay-协议内幕" aria-label="Permalink to &quot;Relay 协议内幕&quot;">​</a></h1><p>Relay 隧道在 Agent 之间传输流量。配合 HTTP 或 L4 规则使用：规则定义入口和后端，Relay 监听器定义 Agent 之间的中间路径。</p><h2 id="传输方式" tabindex="-1">传输方式 <a class="header-anchor" href="#传输方式" aria-label="Permalink to &quot;传输方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>说明</th></tr></thead><tbody><tr><td><code>tls_tcp</code></td><td>TLS over TCP。默认模式，配置最简单，大多数网络都能用</td></tr><tr><td><code>quic</code></td><td>QUIC over UDP。握手延迟更低。防火墙需允许 UDP/QUIC</td></tr><tr><td><code>wireguard</code></td><td>通过 WireGuard 接口传输。Relay 的 TLS、多路复用和认证仍在 WireGuard 上生效</td></tr></tbody></table><h2 id="监听器字段" tabindex="-1">监听器字段 <a class="header-anchor" href="#监听器字段" aria-label="Permalink to &quot;监听器字段&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td>面板显示名称</td></tr><tr><td>证书来源</td><td>默认自动签发（Relay CA）。也可绑定已有证书</td></tr><tr><td>绑定地址</td><td>Agent 本地监听地址，每行一个</td></tr><tr><td>监听端口</td><td>Agent 本地监听端口</td></tr><tr><td>公网入口</td><td>其他节点连接此中继的地址，格式 <code>host</code> 或 <code>host:port</code></td></tr><tr><td>传输方式</td><td>TLS/TCP、QUIC 或 WireGuard</td></tr><tr><td>信任策略</td><td>默认自动 Relay CA + Pin。可在高级设置中自定义</td></tr></tbody></table><h2 id="tls-与信任策略" tabindex="-1">TLS 与信任策略 <a class="header-anchor" href="#tls-与信任策略" aria-label="Permalink to &quot;TLS 与信任策略&quot;">​</a></h2><p>默认使用自动签发的 Relay CA 证书加证书固定（Pin），安全且无需手动配置。</p><p>手动控制时的 TLS 模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>含义</th></tr></thead><tbody><tr><td>Pin + CA</td><td>同时验证固定值和 CA 链（默认）</td></tr><tr><td>仅 Pin</td><td>只验证固定值</td></tr><tr><td>仅 CA</td><td>只验证 CA 链</td></tr><tr><td>Pin 或 CA</td><td>任一通过即接受</td></tr></tbody></table><p>高级设置中可提供「固定集」（每行一个，格式 <code>type:value</code>）和「受信任的 CA 证书」。TLS/TCP 模式还可选 TLS 混淆策略（仅首跳有效）。</p><h2 id="relay-层" tabindex="-1">Relay 层 <a class="header-anchor" href="#relay-层" aria-label="Permalink to &quot;Relay 层&quot;">​</a></h2><p>HTTP 和 L4 规则用 <code>relay_layers</code> 描述隧道路径。每层可包含多个 Relay 监听器作为并行候选，层按顺序处理：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端 → 第 1 层 → 第 2 层 → 后端</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>旧的 <code>relay_chain</code> 字段仅用于向后兼容，新配置用 <code>relay_layers</code>。</p><h2 id="超时变量" tabindex="-1">超时变量 <a class="header-anchor" href="#超时变量" aria-label="Permalink to &quot;超时变量&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>NRE_RELAY_DIAL_TIMEOUT</code></td><td><code>5s</code></td><td>连接上游中继超时</td></tr><tr><td><code>NRE_RELAY_HANDSHAKE_TIMEOUT</code></td><td><code>5s</code></td><td>中继握手超时</td></tr><tr><td><code>NRE_RELAY_FRAME_TIMEOUT</code></td><td><code>5s</code></td><td>单帧读写超时</td></tr><tr><td><code>NRE_RELAY_IDLE_TIMEOUT</code></td><td><code>2m</code></td><td>空闲连接保持时间</td></tr></tbody></table><h2 id="如何使用" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用" aria-label="Permalink to &quot;如何使用&quot;">​</a></h2><p>操作指南见 <a href="./../guides/relay">Relay 隧道</a>。</p>',19)])])}const y=e(o,[["render",l]]);export{b as __pageData,y as default};
